package com.sismptm.partner.data.remote
import retrofit2.Response import retrofit2.http.Body import retrofit2.http.GET import retrofit2.http.POST
interface ApiService {
@GET("ping") suspend fun ping(): Response<PingResponse>
@POST("auth/partner/register") suspend fun registerPartner(@Body registerRequest: RegisterRequest): Response<Unit>
@POST("auth/partner/login") suspend fun loginPartner(@Body loginRequest: LoginRequest): Response<AuthResponse> }
data class PingResponse( val status: String, val timestamp: String )
data class RegisterRequest( val name: String, val email: String, val password: String, val location: String, val creationDate: String )
data class LoginRequest( val email: String, val password: String )
data class AuthResponse( val token: String, val partnerId: String, val partnerName: String )

package com.sismptm.partner.data.remote
import retrofit2.Response import retrofit2.http.Body import retrofit2.http.GET import retrofit2.http.POST
interface ApiService {
@GET("ping") suspend fun ping(): Response<PingResponse>
@POST("auth/partner/register") suspend fun registerPartner(@Body registerRequest: RegisterRequest): Response<Unit>
@POST("auth/partner/login") suspend fun loginPartner(@Body loginRequest: LoginRequest): Response<AuthResponse> }
data class PingResponse( val status: String, val timestamp: String )
data class RegisterRequest( val name: String, val email: String, val password: String, val creationDate: String )
data class LoginRequest( val email: String, val password: String )
data class AuthResponse( val token: String, val partnerId: String, val partnerName: String )

package com.sismptm.partner.ui.screens

internal object RegisterFormValidator {

    const val MIN_PASSWORD_LENGTH = 8
    private val emailRegex = Regex(
        pattern = "^[A-Za-z0-9](?:[A-Za-z0-9._%+-]{0,62}[A-Za-z0-9])?@[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?(?:\\.[A-Za-z]{2,})+$"
    )

    fun isValidEmail(email: String): Boolean {
        return emailRegex.matches(email.trim())
    }

    fun isFormValid(
        fullName: String,
        email: String,
        password: String,
        acceptedTerms: Boolean
    ): Boolean {
        return acceptedTerms &&
                fullName.isNotBlank() &&
                isValidEmail(email) &&
                password.length >= MIN_PASSWORD_LENGTH
    }

}

package com.sismptm.partner.ui.screens

internal object RegisterFormValidator {

    const val MIN_PASSWORD_LENGTH = 8
    private val emailRegex = Regex(
        pattern = "^[A-Za-z0-9](?:[A-Za-z0-9._%+-]{0,62}[A-Za-z0-9])?@[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?(?:\\.[A-Za-z]{2,})+$"
    )

    fun isValidFullName(fullName: String): Boolean {
        return fullName.trim().isNotEmpty()
    }

    fun isValidEmail(email: String): Boolean {
        return emailRegex.matches(email.trim())
    }

    fun isValidPassword(password: String): Boolean {
        return password.isNotBlank() && password.length >= MIN_PASSWORD_LENGTH
    }

    fun doPasswordsMatch(password: String, confirmPassword: String): Boolean {
        return confirmPassword.isNotEmpty() && password == confirmPassword
    }

    fun isFormValid(
        fullName: String,
        email: String,
        password: String,
        acceptedTerms: Boolean
    ): Boolean {
        return acceptedTerms &&
                isValidFullName(fullName) &&
                isValidEmail(email) &&
                isValidPassword(password)
    }

    fun isFormValid(
        fullName: String,
        email: String,
        password: String,
        confirmPassword: String,
        acceptedTerms: Boolean
    ): Boolean {
        return acceptedTerms &&
                isValidFullName(fullName) &&
                isValidEmail(email) &&
                isValidPassword(password) &&
                doPasswordsMatch(password, confirmPassword)
    }

}

package com.sismptm.partner.ui.screens

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.res.stringResource
import androidx.compose.ui.text.input.PasswordVisualTransformation
import androidx.compose.ui.unit.dp
import com.sismptm.partner.R
import java.util.Date

@Composable
fun RegisterScreen(
    onRegisterSuccess: () -> Unit,
    onNavigateToLogin: () -> Unit
) {
    var name by remember { mutableStateOf("") }
    var email by remember { mutableStateOf("") }
    var password by remember { mutableStateOf("") }
    var confirmPassword by remember { mutableStateOf("") }
    var location by remember { mutableStateOf("") }
    var acceptedTerms by remember { mutableStateOf(false) }

    val creationDate = remember { Date().toString() }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.Center
    ) {
        Text(
            text = stringResource(id = R.string.register_title),
            style = MaterialTheme.typography.headlineLarge
        )

        Spacer(modifier = Modifier.height(32.dp))

        OutlinedTextField(
            value = name,
            onValueChange = { name = it },
            label = { Text(stringResource(id = R.string.full_name)) },
            modifier = Modifier.fillMaxWidth()
        )

        Spacer(modifier = Modifier.height(8.dp))

        OutlinedTextField(
            value = email,
            onValueChange = { email = it },
            label = { Text(stringResource(id = R.string.email)) },
            modifier = Modifier.fillMaxWidth()
        )

        Spacer(modifier = Modifier.height(8.dp))

        OutlinedTextField(
            value = password,
            onValueChange = { password = it },
            label = { Text(stringResource(id = R.string.password)) },
            visualTransformation = PasswordVisualTransformation(),
            modifier = Modifier.fillMaxWidth()
        )

        Spacer(modifier = Modifier.height(8.dp))

        OutlinedTextField(
            value = confirmPassword,
            onValueChange = { confirmPassword = it },
            label = { Text(stringResource(id = R.string.confirm_password)) },
            visualTransformation = PasswordVisualTransformation(),
            modifier = Modifier.fillMaxWidth()
        )

        Spacer(modifier = Modifier.height(8.dp))

        // Nuevo atributo: Localización para partner solamente
        OutlinedTextField(
            value = location,
            onValueChange = { location = it },
            label = { Text(stringResource(id = R.string.location)) },
            modifier = Modifier.fillMaxWidth()
        )

        Spacer(modifier = Modifier.height(16.dp))

        Row(
            verticalAlignment = Alignment.CenterVertically,
            modifier = Modifier.fillMaxWidth()
        ) {
            Checkbox(
                checked = acceptedTerms,
                onCheckedChange = { acceptedTerms = it }
            )
            Text(
                text = stringResource(id = R.string.accept_terms),
                style = MaterialTheme.typography.bodyMedium
            )
        }

        Spacer(modifier = Modifier.height(24.dp))

        Button(
            onClick = { 
                // Aquí se usaría 'creationDate' y 'location' para guardarlos
                onRegisterSuccess()
            },
            enabled = acceptedTerms,
            modifier = Modifier.fillMaxWidth()
        ) {
            Text(stringResource(id = R.string.register_button))
        }

        TextButton(onClick = onNavigateToLogin) {
            Text(stringResource(id = R.string.already_have_account))
        }
    }
}

package com.sismptm.partner.ui.screens

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.res.stringResource
import androidx.compose.ui.text.input.PasswordVisualTransformation
import androidx.compose.ui.unit.dp
import com.sismptm.partner.R

@Composable
fun RegisterScreen(
    onRegisterSuccess: () -> Unit,
    onNavigateToLogin: () -> Unit
) {
    var name by remember { mutableStateOf("") }
    var email by remember { mutableStateOf("") }
    var password by remember { mutableStateOf("") }
    var confirmPassword by remember { mutableStateOf("") }
    var acceptedTerms by remember { mutableStateOf(false) }
    val isFormValid = RegisterFormValidator.isFormValid(
        fullName = name,
        email = email,
        password = password,
        confirmPassword = confirmPassword,
        acceptedTerms = acceptedTerms
    )

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.Center
    ) {
        Text(
            text = stringResource(id = R.string.register_title),
            style = MaterialTheme.typography.headlineLarge
        )

        Spacer(modifier = Modifier.height(32.dp))

        OutlinedTextField(
            value = name,
            onValueChange = { name = it },
            label = { Text(stringResource(id = R.string.full_name)) },
            modifier = Modifier.fillMaxWidth()
        )

        Spacer(modifier = Modifier.height(8.dp))

        OutlinedTextField(
            value = email,
            onValueChange = { email = it },
            label = { Text(stringResource(id = R.string.email)) },
            modifier = Modifier.fillMaxWidth()
        )

        Spacer(modifier = Modifier.height(8.dp))

        OutlinedTextField(
            value = password,
            onValueChange = { password = it },
            label = { Text(stringResource(id = R.string.password)) },
            visualTransformation = PasswordVisualTransformation(),
            modifier = Modifier.fillMaxWidth()
        )

        Spacer(modifier = Modifier.height(8.dp))

        OutlinedTextField(
            value = confirmPassword,
            onValueChange = { confirmPassword = it },
            label = { Text(stringResource(id = R.string.confirm_password)) },
            visualTransformation = PasswordVisualTransformation(),
            modifier = Modifier.fillMaxWidth()
        )

        Spacer(modifier = Modifier.height(16.dp))

        Row(
            verticalAlignment = Alignment.CenterVertically,
            modifier = Modifier.fillMaxWidth()
        ) {
            Checkbox(
                checked = acceptedTerms,
                onCheckedChange = { acceptedTerms = it }
            )
            Text(
                text = stringResource(id = R.string.accept_terms),
                style = MaterialTheme.typography.bodyMedium
            )
        }

        Spacer(modifier = Modifier.height(24.dp))

        Button(
            onClick = { 
                if (!isFormValid) {
                    return@Button
                }

                onRegisterSuccess()
            },
            enabled = isFormValid,
            modifier = Modifier.fillMaxWidth()
        ) {
            Text(stringResource(id = R.string.register_button))
        }

        TextButton(onClick = onNavigateToLogin) {
            Text(stringResource(id = R.string.already_have_account))
        }
    }
}

package com.sismptm.partner.ui.screens

import org.junit.Assert.assertFalse
import org.junit.Assert.assertTrue
import org.junit.Test

class RegisterFormValidatorTest {

    @Test
    fun isValidEmail_acceptsTrimmedValidEmail() {
        assertTrue(RegisterFormValidator.isValidEmail("  partner@example.com  "))
    }

    @Test
    fun isValidEmail_rejectsInvalidEmail() {
        assertFalse(RegisterFormValidator.isValidEmail("partner.example.com"))
    }

    @Test
    fun isValidPassword_rejectsBlankOrShortPassword() {
        assertFalse(RegisterFormValidator.isValidPassword("        "))
        assertFalse(RegisterFormValidator.isValidPassword("short7"))
    }

    @Test
    fun isValidPassword_acceptsPasswordWithExactMinimumLength() {
        assertTrue(RegisterFormValidator.isValidPassword("abcd1234"))
    }

    @Test
    fun doPasswordsMatch_rejectsEmptyConfirmation() {
        assertFalse(RegisterFormValidator.doPasswordsMatch("segura123", ""))
    }

    @Test
    fun isFormValid_basicOverload_acceptsValidData() {
        assertTrue(
            RegisterFormValidator.isFormValid(
                fullName = "Ana Pérez",
                email = "ana@example.com",
                password = "segura123",
                acceptedTerms = true
            )
        )
    }

    @Test
    fun isFormValid_basicOverload_rejectsWhenTermsAreNotAccepted() {
        assertFalse(
            RegisterFormValidator.isFormValid(
                fullName = "Ana Pérez",
                email = "ana@example.com",
                password = "segura123",
                acceptedTerms = false
            )
        )
    }

    @Test
    fun isFormValid_fullOverload_acceptsCompleteValidForm() {
        assertTrue(
            RegisterFormValidator.isFormValid(
                fullName = "Ana Pérez",
                email = "ana@example.com",
                password = "segura123",
                confirmPassword = "segura123",
                acceptedTerms = true
            )
        )
    }

    @Test
    fun isFormValid_fullOverload_rejectsWhenPasswordsDoNotMatch() {
        assertFalse(
            RegisterFormValidator.isFormValid(
                fullName = "Ana Pérez",
                email = "ana@example.com",
                password = "segura123",
                confirmPassword = "segura124",
                acceptedTerms = true
            )
        )
    }

    @Test
    fun isFormValid_fullOverload_rejectsInvalidEmail() {
        assertFalse(
            RegisterFormValidator.isFormValid(
                fullName = "Ana Pérez",
                email = "ana.example.com",
                password = "segura123",
                confirmPassword = "segura123",
                acceptedTerms = true
            )
        )
    }

    @Test
    fun isFormValid_fullOverload_rejectsWhenTermsAreNotAccepted() {
        assertFalse(
            RegisterFormValidator.isFormValid(
                fullName = "Ana Pérez",
                email = "ana@example.com",
                password = "segura123",
                confirmPassword = "segura123",
                acceptedTerms = false
            )
        )
    }

    @Test
    fun isFormValid_fullOverload_rejectsBlankFullNameEvenWithSpaces() {
        assertFalse(
            RegisterFormValidator.isFormValid(
                fullName = "   ",
                email = "ana@example.com",
                password = "segura123",
                confirmPassword = "segura123",
                acceptedTerms = true
            )
        )
    }
}
